int main(int argc, char ** argv) {
    struct model m;
    model_init(&m);
    load_weights(&m, "yolov5n_weights_folded.bin");
    struct ggml_init_params p = { .mem_size = 512*1024*1024, .mem_buffer = NULL, .no_alloc = false };
    struct ggml_context * ctx = ggml_init(p);
    struct ggml_tensor * input = ggml_new_tensor_4d(ctx, GGML_TYPE_F32, 640, 640, 3, 1);
    ggml_set_name(input, "input");
    struct ggml_tensor * output = model_forward(&m, ctx, input);
    /* Build compute graph */
    struct ggml_cgraph * gf = ggml_new_graph(ctx);
    ggml_build_forward_expand(gf, output);
    
    /* Fill input with test data (same seed as PyTorch reference) */
    {
        /* Read input from file dumped by PyTorch */
        FILE * fin = fopen("layer_dumps/input.bin", "rb");
        if (fin) {
            fread(input->data, 1, ggml_nbytes(input), fin);
            fclose(fin);
            printf("Loaded input from layer_dumps/input.bin\n");
        } else {
            printf("WARNING: could not load input.bin, using zeros\n");
        }
    }
    
    /* Compute */
    int n_threads = 1;  /* single thread for deterministic results */
    ggml_graph_compute_with_ctx(ctx, gf, n_threads);
    
    printf("Forward pass computed. Output shape: [%lld, %lld, %lld, %lld]\n",
           output->ne[0], output->ne[1], output->ne[2], output->ne[3]);
    
    /* Dump output for comparison */
    {
        FILE * fout = fopen("layer_dumps/ggml_output.bin", "wb");
        if (fout) {
            fwrite(output->data, 1, ggml_nbytes(output), fout);
            fclose(fout);
            printf("Saved output to layer_dumps/ggml_output.bin (%zu bytes)\n", ggml_nbytes(output));
        }
    }
    
    ggml_free(ctx);
    ggml_free(m.ctx_w);
    return 0;
}